r 1|September 1st]] |- | [[Iwashimizu Hachimangū|Iwashimizu Hachiman Shrine]] | [[September 15]] |- | {{ill|Dazaifu Tenmangū|ja|太宰府天満宮|en|6=simple|7=User:Immanuelle/Dazaifu Tenmangū|qq=draft|qq=draft|qq=draft|12=simple|13=User:Immanuelle/Dazaifu Tenmangū|qq=}} | [[September 25]] |- | {{ill|Mononobe Shrine|ja|物部神社_(大田市)|en|6=simple|7=User:Immanuelle/Mononobe Shrine|qq=draft|qq=draft|qq=draft|12=simple|13=User:Immanuelle/Mononobe Shrine|qq=}} | [[October 9]] |- | {{ill|Isonokami Jingu|lt=Isonokami Jingu|lt=Isonokami Shrine|ja|石上神宮|en|6=simple|7=User:Immanuelle/Isonokami Shrine|qq=draft|qq=draft|qq=draft|12=simple|13=User:Immanuelle/Isonokami Shrine|qq=}} | [[October 15]] |- | {{ill|Meiji Jingu|lt=Meiji Jingu|lt=Meiji Shrine|ja|明治神宮|en|qq=draft|qq=draft|qq=draft|12=simple|13=User:Immanuelle/Meiji Shrine|qq=}} | [[November 3]] |}
